# solution.py
"""Team collaboration manager.

A thread-safe, in-memory backend for managing users, projects, tasks,
messages, performance metrics and reports. Standard library only, ASCII only.

The public surface is :class:`TeamCollaborationManager`, a facade that
delegates to a set of stores and services. Every store and service shares a
single re-entrant lock (exposed as ``_lock``) so that concurrent access is
serialized and entity identifiers stay globally unique.
"""

import csv
import io
import threading
from collections import defaultdict
from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum
from typing import Callable, Dict, List, Optional, Tuple


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class UserRole(Enum):
    """Role assigned to a user."""

    MEMBER = "member"
    ADMIN = "admin"


class TaskStatus(Enum):
    """Lifecycle status of a task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class ReportFormat(Enum):
    """Supported export formats."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    """Kinds of report the manager can produce."""

    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for all errors raised by the manager."""


class ValidationError(TeamCollaborationError):
    """Raised when an argument fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an action."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint would be violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with current state."""


# ---------------------------------------------------------------------------
# Data entities
# ---------------------------------------------------------------------------
@dataclass
class Attachment:
    """Metadata describing a file attached to a message."""

    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime

    def clone(self) -> "Attachment":
        return Attachment(
            filename=self.filename,
            size=self.size,
            uploaded_by=self.uploaded_by,
            uploaded_at=self.uploaded_at,
        )


@dataclass
class User:
    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime

    def clone(self) -> "User":
        return User(
            id=self.id,
            username=self.username,
            email=self.email,
            role=self.role,
            created_at=self.created_at,
        )


@dataclass
class Project:
    id: int
    name: str
    start_date: datetime
    end_date: datetime
    owner_id: int
    description: str = ""
    created_at: Optional[datetime] = None

    def clone(self) -> "Project":
        return Project(
            id=self.id,
            name=self.name,
            start_date=self.start_date,
            end_date=self.end_date,
            owner_id=self.owner_id,
            description=self.description,
            created_at=self.created_at,
        )


@dataclass
class Task:
    id: int
    project_id: int
    title: str
    status: TaskStatus = TaskStatus.NOT_STARTED
    assignee_id: Optional[int] = None
    deadline: Optional[datetime] = None
    created_at: Optional[datetime] = None
    started_at: Optional[datetime] = None
    completed_at: Optional[datetime] = None

    def clone(self) -> "Task":
        return Task(
            id=self.id,
            project_id=self.project_id,
            title=self.title,
            status=self.status,
            assignee_id=self.assignee_id,
            deadline=self.deadline,
            created_at=self.created_at,
            started_at=self.started_at,
            completed_at=self.completed_at,
        )


@dataclass
class Message:
    id: int
    author_id: int
    body: str
    project_id: Optional[int] = None
    task_id: Optional[int] = None
    parent_id: Optional[int] = None
    attachments: List[Attachment] = field(default_factory=list)
    created_at: Optional[datetime] = None
    edited_at: Optional[datetime] = None

    def clone(self) -> "Message":
        return Message(
            id=self.id,
            author_id=self.author_id,
            body=self.body,
            project_id=self.project_id,
            task_id=self.task_id,
            parent_id=self.parent_id,
            attachments=[a.clone() for a in self.attachments],
            created_at=self.created_at,
            edited_at=self.edited_at,
        )


@dataclass
class Rating:
    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str = ""
    task_id: Optional[int] = None
    created_at: Optional[datetime] = None

    def clone(self) -> "Rating":
        return Rating(
            id=self.id,
            rater_id=self.rater_id,
            ratee_id=self.ratee_id,
            score=self.score,
            feedback=self.feedback,
            task_id=self.task_id,
            created_at=self.created_at,
        )


# ---------------------------------------------------------------------------
# Validation helpers
# ---------------------------------------------------------------------------
def _is_blank(value) -> bool:
    return value is None or not str(value).strip()


def _valid_email(email) -> bool:
    if not isinstance(email, str):
        return False
    email = email.strip()
    if not email or "@" not in email:
        return False
    local, _, domain = email.partition("@")
    return bool(local) and bool(domain)


# ---------------------------------------------------------------------------
# Shared repository: data, indexes, lock and identifier generation
# ---------------------------------------------------------------------------
class _Repository:
    """Holds all mutable state behind a single shared re-entrant lock."""

    def __init__(self, now: Callable[[], datetime]):
        self.now = now
        self.lock = threading.RLock()
        self._next_id = 0

        self.users: Dict[int, User] = {}
        self.projects: Dict[int, Project] = {}
        self.tasks: Dict[int, Task] = {}
        self.messages: Dict[int, Message] = {}
        self.ratings: Dict[int, Rating] = {}

        self.username_index: Dict[str, int] = {}
        self.email_index: Dict[str, int] = {}

        self.tasks_by_project: Dict[int, List[int]] = defaultdict(list)
        self.tasks_by_assignee: Dict[int, List[int]] = defaultdict(list)
        self.messages_by_project: Dict[int, List[int]] = defaultdict(list)
        self.messages_by_task: Dict[int, List[int]] = defaultdict(list)
        self.ratings_by_ratee: Dict[int, List[int]] = defaultdict(list)

    def new_id(self) -> int:
        """Return a process-wide unique identifier. Caller must hold the lock."""
        self._next_id += 1
        return self._next_id

    # -- internal lookups (assume the lock is held) -------------------------
    def require_user(self, user_id: int) -> User:
        user = self.users.get(user_id)
        if user is None:
            raise NotFoundError("user {0} not found".format(user_id))
        return user

    def require_project(self, project_id: int) -> Project:
        project = self.projects.get(project_id)
        if project is None:
            raise NotFoundError("project {0} not found".format(project_id))
        return project

    def require_task(self, task_id: int) -> Task:
        task = self.tasks.get(task_id)
        if task is None:
            raise NotFoundError("task {0} not found".format(task_id))
        return task

    def require_message(self, message_id: int) -> Message:
        message = self.messages.get(message_id)
        if message is None:
            raise NotFoundError("message {0} not found".format(message_id))
        return message

    def tasks_for_assignee(self, user_id: int) -> List[Task]:
        ids = self.tasks_by_assignee.get(user_id, [])
        tasks = [self.tasks[t] for t in ids if t in self.tasks]
        tasks.sort(key=lambda t: t.id)
        return tasks


class _BaseStore:
    """Common base giving every store the shared lock and repository."""

    def __init__(self, repo: _Repository):
        self._repo = repo
        self._lock = repo.lock


# ---------------------------------------------------------------------------
# User store
# ---------------------------------------------------------------------------
class UserStore(_BaseStore):
    def register(self, username, email, role=UserRole.MEMBER) -> User:
        with self._lock:
            if _is_blank(username):
                raise ValidationError("username must not be empty")
            if not _valid_email(email):
                raise ValidationError("invalid email address")
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")
            if username in self._repo.username_index:
                raise DuplicateError("username already in use")
            if email in self._repo.email_index:
                raise DuplicateError("email already in use")

            user_id = self._repo.new_id()
            user = User(
                id=user_id,
                username=username,
                email=email,
                role=role,
                created_at=self._repo.now(),
            )
            self._repo.users[user_id] = user
            self._repo.username_index[username] = user_id
            self._repo.email_index[email] = user_id
            return user.clone()

    def get(self, user_id) -> User:
        with self._lock:
            return self._repo.require_user(user_id).clone()

    def list(self) -> List[User]:
        with self._lock:
            users = sorted(self._repo.users.values(), key=lambda u: u.id)
            return [u.clone() for u in users]

    def update(self, user_id, username=None, email=None, role=None) -> User:
        with self._lock:
            user = self._repo.require_user(user_id)

            if username is not None and _is_blank(username):
                raise ValidationError("username must not be empty")
            if email is not None and not _valid_email(email):
                raise ValidationError("invalid email address")
            if role is not None and not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            if username is not None and username != user.username:
                if username in self._repo.username_index:
                    raise DuplicateError("username already in use")
            if email is not None and email != user.email:
                if email in self._repo.email_index:
                    raise DuplicateError("email already in use")

            if username is not None and username != user.username:
                del self._repo.username_index[user.username]
                self._repo.username_index[username] = user.id
                user.username = username
            if email is not None and email != user.email:
                del self._repo.email_index[user.email]
                self._repo.email_index[email] = user.id
                user.email = email
            if role is not None:
                user.role = role
            return user.clone()

    def delete(self, user_id) -> None:
        with self._lock:
            user = self._repo.require_user(user_id)

            for project in self._repo.projects.values():
                if project.owner_id == user_id:
                    raise ConflictError("user owns a project")

            for task in self._repo.tasks_for_assignee(user_id):
                if task.status != TaskStatus.COMPLETED:
                    raise ConflictError("user has an open task")

            del self._repo.users[user_id]
            self._repo.username_index.pop(user.username, None)
            self._repo.email_index.pop(user.email, None)
            self._repo.tasks_by_assignee.pop(user_id, None)


# ---------------------------------------------------------------------------
# Project store
# ---------------------------------------------------------------------------
class ProjectStore(_BaseStore):
    def create(self, name, start_date, end_date, owner_id, description="") -> Project:
        with self._lock:
            self._repo.require_user(owner_id)
            if _is_blank(name):
                raise ValidationError("project name must not be empty")
            if end_date < start_date:
                raise ValidationError("end date must not be before start date")

            project_id = self._repo.new_id()
            project = Project(
                id=project_id,
                name=name,
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                description=description or "",
                created_at=self._repo.now(),
            )
            self._repo.projects[project_id] = project
            return project.clone()

    def get(self, project_id) -> Project:
        with self._lock:
            return self._repo.require_project(project_id).clone()

    def list(self) -> List[Project]:
        with self._lock:
            projects = sorted(self._repo.projects.values(), key=lambda p: p.id)
            return [p.clone() for p in projects]

    def update(self, project_id, name=None, start_date=None, end_date=None,
               description=None) -> Project:
        with self._lock:
            project = self._repo.require_project(project_id)

            if name is not None and _is_blank(name):
                raise ValidationError("project name must not be empty")

            new_start = project.start_date if start_date is None else start_date
            new_end = project.end_date if end_date is None else end_date
            if new_end < new_start:
                raise ValidationError("end date must not be before start date")

            if name is not None:
                project.name = name
            if start_date is not None:
                project.start_date = start_date
            if end_date is not None:
                project.end_date = end_date
            if description is not None:
                project.description = description
            return project.clone()

    def delete(self, project_id) -> None:
        with self._lock:
            self._repo.require_project(project_id)

            for task_id in list(self._repo.tasks_by_project.get(project_id, [])):
                task = self._repo.tasks.pop(task_id, None)
                if task is not None and task.assignee_id is not None:
                    assignee_tasks = self._repo.tasks_by_assignee.get(task.assignee_id)
                    if assignee_tasks and task_id in assignee_tasks:
                        assignee_tasks.remove(task_id)
                for message_id in list(self._repo.messages_by_task.get(task_id, [])):
                    self._repo.messages.pop(message_id, None)
                self._repo.messages_by_task.pop(task_id, None)
            self._repo.tasks_by_project.pop(project_id, None)

            for message_id in list(self._repo.messages_by_project.get(project_id, [])):
                self._repo.messages.pop(message_id, None)
            self._repo.messages_by_project.pop(project_id, None)

            del self._repo.projects[project_id]


# ---------------------------------------------------------------------------
# Task store
# ---------------------------------------------------------------------------
class TaskStore(_BaseStore):
    def create(self, project_id, title, assignee_id=None, deadline=None) -> Task:
        with self._lock:
            project = self._repo.require_project(project_id)
            if _is_blank(title):
                raise ValidationError("task title must not be empty")
            if assignee_id is not None:
                self._repo.require_user(assignee_id)
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline must not precede project start")

            task_id = self._repo.new_id()
            task = Task(
                id=task_id,
                project_id=project_id,
                title=title,
                status=TaskStatus.NOT_STARTED,
                assignee_id=assignee_id,
                deadline=deadline,
                created_at=self._repo.now(),
            )
            self._repo.tasks[task_id] = task
            self._repo.tasks_by_project[project_id].append(task_id)
            if assignee_id is not None:
                self._repo.tasks_by_assignee[assignee_id].append(task_id)
            return task.clone()

    def get(self, task_id) -> Task:
        with self._lock:
            return self._repo.require_task(task_id).clone()

    def list_by_project(self, project_id) -> List[Task]:
        with self._lock:
            self._repo.require_project(project_id)
            ids = self._repo.tasks_by_project.get(project_id, [])
            tasks = sorted(
                (self._repo.tasks[t] for t in ids if t in self._repo.tasks),
                key=lambda t: t.id,
            )
            return [t.clone() for t in tasks]

    def list_by_assignee(self, assignee_id) -> List[Task]:
        with self._lock:
            self._repo.require_user(assignee_id)
            return [t.clone() for t in self._repo.tasks_for_assignee(assignee_id)]

    def _set_assignee(self, task: Task, new_assignee: Optional[int]) -> None:
        old = task.assignee_id
        if old is not None:
            current = self._repo.tasks_by_assignee.get(old)
            if current and task.id in current:
                current.remove(task.id)
        task.assignee_id = new_assignee
        if new_assignee is not None:
            self._repo.tasks_by_assignee[new_assignee].append(task.id)

    def assign(self, task_id, assignee_id) -> Task:
        with self._lock:
            task = self._repo.require_task(task_id)
            self._repo.require_user(assignee_id)
            self._set_assignee(task, assignee_id)
            return task.clone()

    def reassign(self, task_id, new_assignee_id) -> Task:
        with self._lock:
            task = self._repo.require_task(task_id)
            self._repo.require_user(new_assignee_id)
            self._set_assignee(task, new_assignee_id)
            return task.clone()

    def unassign(self, task_id) -> Task:
        with self._lock:
            task = self._repo.require_task(task_id)
            self._set_assignee(task, None)
            return task.clone()

    def set_deadline(self, task_id, deadline) -> Task:
        with self._lock:
            task = self._repo.require_task(task_id)
            if deadline is not None:
                project = self._repo.projects.get(task.project_id)
                start = project.start_date if project is not None else None
                if start is not None and deadline < start:
                    raise ValidationError("deadline must not precede project start")
            task.deadline = deadline
            return task.clone()

    def update_status(self, task_id, status) -> Task:
        with self._lock:
            task = self._repo.require_task(task_id)
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")

            now = self._repo.now()
            if status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            else:  # NOT_STARTED
                task.started_at = None
                task.completed_at = None
            task.status = status
            return task.clone()


# ---------------------------------------------------------------------------
# Message store
# ---------------------------------------------------------------------------
class MessageStore(_BaseStore):
    def post(self, author_id, body, project_id=None, task_id=None,
             attachments=None, parent_id=None) -> Message:
        with self._lock:
            self._repo.require_user(author_id)

            has_project = project_id is not None
            has_task = task_id is not None
            if has_project == has_task:
                raise ValidationError(
                    "message must target exactly one of project or task"
                )
            if has_project:
                self._repo.require_project(project_id)
            if has_task:
                self._repo.require_task(task_id)
            if parent_id is not None:
                self._repo.require_message(parent_id)

            attachments = attachments or []
            if _is_blank(body) and not attachments:
                raise ValidationError("message body or attachment required")

            now = self._repo.now()
            attachment_objs = [
                Attachment(
                    filename=filename,
                    size=len(data),
                    uploaded_by=author_id,
                    uploaded_at=now,
                )
                for filename, data in attachments
            ]

            message_id = self._repo.new_id()
            message = Message(
                id=message_id,
                author_id=author_id,
                body=body,
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                attachments=attachment_objs,
                created_at=now,
                edited_at=None,
            )
            self._repo.messages[message_id] = message
            if has_project:
                self._repo.messages_by_project[project_id].append(message_id)
            if has_task:
                self._repo.messages_by_task[task_id].append(message_id)
            return message.clone()

    def edit(self, message_id, editor_id, new_body) -> Message:
        with self._lock:
            message = self._repo.require_message(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may edit a message")
            if _is_blank(new_body) and not message.attachments:
                raise ValidationError("message body must not be empty")
            message.body = new_body
            message.edited_at = self._repo.now()
            return message.clone()

    def add_attachment(self, message_id, user_id, filename, data) -> Message:
        with self._lock:
            message = self._repo.require_message(message_id)
            if message.author_id != user_id:
                raise AuthorizationError("only the author may attach files")
            if _is_blank(filename):
                raise ValidationError("filename must not be empty")
            message.attachments.append(
                Attachment(
                    filename=filename,
                    size=len(data),
                    uploaded_by=user_id,
                    uploaded_at=self._repo.now(),
                )
            )
            return message.clone()

    def list_by_project(self, project_id) -> List[Message]:
        with self._lock:
            self._repo.require_project(project_id)
            ids = self._repo.messages_by_project.get(project_id, [])
            messages = sorted(
                (self._repo.messages[m] for m in ids if m in self._repo.messages),
                key=lambda m: m.id,
            )
            return [m.clone() for m in messages]

    def list_by_task(self, task_id) -> List[Message]:
        with self._lock:
            self._repo.require_task(task_id)
            ids = self._repo.messages_by_task.get(task_id, [])
            messages = sorted(
                (self._repo.messages[m] for m in ids if m in self._repo.messages),
                key=lambda m: m.id,
            )
            return [m.clone() for m in messages]

    def delete(self, message_id, user_id) -> None:
        with self._lock:
            message = self._repo.require_message(message_id)
            if message.author_id != user_id:
                raise AuthorizationError("only the author may delete a message")
            if message.project_id is not None:
                lst = self._repo.messages_by_project.get(message.project_id)
                if lst and message_id in lst:
                    lst.remove(message_id)
            if message.task_id is not None:
                lst = self._repo.messages_by_task.get(message.task_id)
                if lst and message_id in lst:
                    lst.remove(message_id)
            del self._repo.messages[message_id]


# ---------------------------------------------------------------------------
# Shared task-statistics helper
# ---------------------------------------------------------------------------
def _task_stats(tasks: List[Task]) -> dict:
    total = len(tasks)
    completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
    in_progress = sum(1 for t in tasks if t.status == TaskStatus.IN_PROGRESS)
    not_started = sum(1 for t in tasks if t.status == TaskStatus.NOT_STARTED)
    rate = (completed / total) if total else 0.0

    durations = [
        (t.completed_at - t.started_at).total_seconds()
        for t in tasks
        if t.status == TaskStatus.COMPLETED
        and t.started_at is not None
        and t.completed_at is not None
    ]
    average_time = (sum(durations) / len(durations)) if durations else None

    return {
        "total_tasks": total,
        "completed_tasks": completed,
        "in_progress_tasks": in_progress,
        "not_started_tasks": not_started,
        "completion_rate": rate,
        "average_completion_time": average_time,
    }


# ---------------------------------------------------------------------------
# Performance service
# ---------------------------------------------------------------------------
class PerformanceService(_BaseStore):
    def get_completion_rate(self, user_id) -> float:
        with self._lock:
            self._repo.require_user(user_id)
            return _task_stats(self._repo.tasks_for_assignee(user_id))["completion_rate"]

    def get_average_completion_time(self, user_id) -> Optional[float]:
        with self._lock:
            self._repo.require_user(user_id)
            return _task_stats(
                self._repo.tasks_for_assignee(user_id)
            )["average_completion_time"]

    def _rating_summary(self, user_id) -> Tuple[int, float, List[Rating]]:
        ids = self._repo.ratings_by_ratee.get(user_id, [])
        ratings = sorted(
            (self._repo.ratings[r] for r in ids if r in self._repo.ratings),
            key=lambda r: r.id,
        )
        count = len(ratings)
        average = (sum(r.score for r in ratings) / count) if count else 0.0
        return count, average, ratings

    def submit_rating(self, rater_id, ratee_id, score, feedback="", task_id=None) -> Rating:
        with self._lock:
            self._repo.require_user(rater_id)
            self._repo.require_user(ratee_id)
            if rater_id == ratee_id:
                raise ConflictError("users may not rate themselves")
            if isinstance(score, bool) or not isinstance(score, int):
                raise ValidationError("score must be an integer")
            if score < 1 or score > 5:
                raise ValidationError("score must be between 1 and 5")
            if task_id is not None:
                self._repo.require_task(task_id)

            rating_id = self._repo.new_id()
            rating = Rating(
                id=rating_id,
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback or "",
                task_id=task_id,
                created_at=self._repo.now(),
            )
            self._repo.ratings[rating_id] = rating
            self._repo.ratings_by_ratee[ratee_id].append(rating_id)
            return rating.clone()

    def get_ratings_summary(self, user_id) -> dict:
        with self._lock:
            self._repo.require_user(user_id)
            count, average, ratings = self._rating_summary(user_id)
            return {
                "count": count,
                "average": average,
                "ratings": [r.clone() for r in ratings],
            }

    def get_user_dashboard(self, user_id) -> dict:
        with self._lock:
            self._repo.require_user(user_id)
            stats = _task_stats(self._repo.tasks_for_assignee(user_id))
            count, average, _ = self._rating_summary(user_id)
            dashboard = dict(stats)
            dashboard["rating_count"] = count
            dashboard["rating_average"] = average
            return dashboard


