# Reports service
# ---------------------------------------------------------------------------
class ReportsService(_BaseStore):
    def project_progress_report(self, project_id) -> dict:
        with self._lock:
            project = self._repo.require_project(project_id)
            ids = self._repo.tasks_by_project.get(project_id, [])
            tasks = [self._repo.tasks[t] for t in ids if t in self._repo.tasks]
            now = self._repo.now()

            status_counts = {status.value: 0 for status in TaskStatus}
            overdue = 0
            per_assignee: Dict[int, List[Task]] = defaultdict(list)
            for task in tasks:
                status_counts[task.status.value] += 1
                if (
                    task.deadline is not None
                    and task.deadline < now
                    and task.status != TaskStatus.COMPLETED
                ):
                    overdue += 1
                if task.assignee_id is not None:
                    per_assignee[task.assignee_id].append(task)

            total = len(tasks)
            completed = status_counts[TaskStatus.COMPLETED.value]
            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project.id,
                "project_name": project.name,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": (completed / total) if total else 0.0,
                "overdue_tasks": overdue,
                "per_assignee": {
                    uid: _task_stats(items) for uid, items in per_assignee.items()
                },
            }

    def team_performance_report(self, project_id=None) -> dict:
        with self._lock:
            if project_id is not None:
                self._repo.require_project(project_id)

            tasks_by_user: Dict[int, List[Task]] = defaultdict(list)
            for task in self._repo.tasks.values():
                if project_id is not None and task.project_id != project_id:
                    continue
                if task.assignee_id is None:
                    continue
                if task.assignee_id not in self._repo.users:
                    continue
                tasks_by_user[task.assignee_id].append(task)

            rows = []
            for user_id in sorted(tasks_by_user):
                stats = _task_stats(tasks_by_user[user_id])
                count, average, _ = PerformanceService(
                    self._repo
                )._rating_summary(user_id)
                user = self._repo.users.get(user_id)
                row = {
                    "user_id": user_id,
                    "username": user.username if user else "",
                    "total_tasks": stats["total_tasks"],
                    "completed_tasks": stats["completed_tasks"],
                    "completion_rate": stats["completion_rate"],
                    "average_completion_time": stats["average_completion_time"],
                    "rating_count": count,
                    "rating_average": average,
                }
                rows.append(row)

            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "scope_project_id": project_id,
                "rows": rows,
            }

    def individual_performance_report(self, user_id) -> dict:
        with self._lock:
            self._repo.require_user(user_id)
            tasks = self._repo.tasks_for_assignee(user_id)
            stats = _task_stats(tasks)
            count, average, _ = PerformanceService(self._repo)._rating_summary(user_id)
            user = self._repo.users.get(user_id)
            report = {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "username": user.username if user else "",
                "tasks": [t.clone() for t in tasks],
                "rating_count": count,
                "rating_average": average,
            }
            report.update(stats)
            return report

    # -- export -------------------------------------------------------------
    def export_report(self, report, report_format):
        with self._lock:
            if not isinstance(report, dict):
                raise ValidationError("report must be a dict")
            if not isinstance(report_format, ReportFormat):
                raise ValidationError("report_format must be a ReportFormat")
            if report_format == ReportFormat.CSV:
                return self._to_csv(report)
            return self._to_pdf(report)

    @staticmethod
    def _to_csv(report) -> str:
        buffer = io.StringIO()
        writer = csv.writer(buffer)
        report_type = report.get("report_type")

        if report_type == ReportType.TEAM_PERFORMANCE.value:
            header = [
                "user_id", "username", "total_tasks", "completed_tasks",
                "completion_rate", "average_completion_time",
                "rating_count", "rating_average",
            ]
            writer.writerow(header)
            for row in report.get("rows", []):
                writer.writerow([row.get(key, "") for key in header])
        elif report_type == ReportType.PROJECT_PROGRESS.value:
            writer.writerow(["metric", "value"])
            writer.writerow(["project_id", report.get("project_id", "")])
            writer.writerow(["project_name", report.get("project_name", "")])
            writer.writerow(["total_tasks", report.get("total_tasks", 0)])
            for status, count in report.get("status_counts", {}).items():
                writer.writerow([status, count])
            writer.writerow(["completion_rate", report.get("completion_rate", 0.0)])
            writer.writerow(["overdue_tasks", report.get("overdue_tasks", 0)])
        elif report_type == ReportType.INDIVIDUAL_PERFORMANCE.value:
            writer.writerow(["metric", "value"])
            for key in (
                "user_id", "username", "total_tasks", "completed_tasks",
                "in_progress_tasks", "not_started_tasks", "completion_rate",
                "average_completion_time", "rating_count", "rating_average",
            ):
                writer.writerow([key, report.get(key, "")])
        else:
            writer.writerow(["key", "value"])
            for key, value in report.items():
                if value is None or isinstance(value, (str, int, float, bool)):
                    writer.writerow([key, value])
        return buffer.getvalue()

    @staticmethod
    def _to_pdf(report) -> bytes:
        report_type = report.get("report_type", "report")
        lines = ["Report: {0}".format(report_type)]
        if report_type == ReportType.TEAM_PERFORMANCE.value:
            lines.append("Rows: {0}".format(len(report.get("rows", []))))
        elif report_type == ReportType.PROJECT_PROGRESS.value:
            lines.append("Project: {0}".format(report.get("project_name", "")))
            lines.append("Total tasks: {0}".format(report.get("total_tasks", 0)))
            lines.append("Completion rate: {0}".format(report.get("completion_rate", 0.0)))
            lines.append("Overdue tasks: {0}".format(report.get("overdue_tasks", 0)))
        elif report_type == ReportType.INDIVIDUAL_PERFORMANCE.value:
            lines.append("User: {0}".format(report.get("username", "")))
            lines.append("Total tasks: {0}".format(report.get("total_tasks", 0)))
            lines.append("Completed: {0}".format(report.get("completed_tasks", 0)))
        return _build_pdf(lines)


# ---------------------------------------------------------------------------
# Minimal PDF generation (standard library only)
# ---------------------------------------------------------------------------
def _pdf_text_stream(lines: List[str]) -> bytes:
    parts = [b"BT", b"/F1 12 Tf", b"72 720 Td", b"14 TL"]
    first = True
    for line in lines:
        escaped = (
            str(line)
            .replace("\\", "\\\\")
            .replace("(", "\\(")
            .replace(")", "\\)")
        )
        encoded = escaped.encode("latin-1", "replace")
        if first:
            parts.append(b"(" + encoded + b") Tj")
            first = False
        else:
            parts.append(b"T*")
            parts.append(b"(" + encoded + b") Tj")
    parts.append(b"ET")
    return b"\n".join(parts)


def _build_pdf(lines: List[str]) -> bytes:
    content = _pdf_text_stream(lines)
    bodies = [
        b"<< /Type /Catalog /Pages 2 0 R >>",
        b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
        (
            b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
            b"/Resources << /Font << /F1 5 0 R >> >> /Contents 4 0 R >>"
        ),
        (
            b"<< /Length " + str(len(content)).encode("ascii") + b" >>\n"
            b"stream\n" + content + b"\nendstream"
        ),
        b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
    ]

    out = bytearray(b"%PDF-1.4\n")
    offsets = []
    for index, body in enumerate(bodies, start=1):
        offsets.append(len(out))
        out += str(index).encode("ascii") + b" 0 obj\n" + body + b"\nendobj\n"

    xref_position = len(out)
    size = len(bodies) + 1
    out += b"xref\n0 " + str(size).encode("ascii") + b"\n"
    out += b"0000000000 65535 f \n"
    for offset in offsets:
        out += "{0:010d} 00000 n \n".format(offset).encode("ascii")
    out += b"trailer\n<< /Size " + str(size).encode("ascii") + b" /Root 1 0 R >>\n"
    out += b"startxref\n" + str(xref_position).encode("ascii") + b"\n%%EOF"
    return bytes(out)


